var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이게…… 우리들의 첫 게임…… 카운터즈 사가……?","JPN":"これが……僕たちの初のゲーム……カウンターズ・サーガ……？","ENG":"This is... our first game...! Counters Saga...","TWN":"這是……我們的第一個遊戲…… 制裁者傳奇……？"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오호!? 쌔삥이라 따끈따근한데? 이 정도면 진짜로 대박 칠 거 같지 않나?","JPN":"おお！？　出来立てほやほややん！　これならホンマに大ヒットしそうやな？","ENG":"Aha! Hot off the press! This is going to be a show stopper for sure!","TWN":"哇喔！？是剛做好的嗎？還熱熱的呢？這應該會大賣吧？"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응응, 너무 귀엽게 나온 거 같아. 역시 박스 군은 대단해!","JPN":"うんうん、とてもかわいくできたと思う。やっぱりダンボール君はすごい！","ENG":"Yes, it’s so cute! You’re awesome, Boxie!","TWN":"嗯嗯，超可愛的，紙箱小朋友真的好厲害！"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하하, 아니에요.","JPN":"はは、とんでもないです。","ENG":"Ha ha, thanks.","TWN":"哈哈，沒有啦。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"SD 캐릭터는 자신 없었는데…… 그래도 실제로 프린팅된 걸 보니까 그럭저럭 잘 나온 것 같아서 기뻐요.","JPN":"SDキャラは自信なかったんですけど……でも実際にプリントされたのを見ると、まあまあの出来なので嬉しいです。","ENG":"I’m not too confident with SD art styles... But looking at how it got printed out, I guess it’s okay.","TWN":"SD角色我沒什麼把握……不過看到實際呈現後，成果很不錯呢，真開心。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라노? 아무나 이렇게 못 그린다 안 하나. 이건 니만 할 수 있는 거라고.","JPN":"何言ってんねん。普通はこうは描けへんて。これはあんたにしかできへんよ。","ENG":"What's that ya say? It ain’t common bein’ able to draw like Picasso! That's somethin’ only you can do, kiddo.","TWN":"說啥呢？這可不是誰都畫得出來的，只有你可以。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니는 좀 더 자신감을 가져도 된다! 마, 가슴도 좀 더 쫙 펴고!","JPN":"あんたはもっと自信持ちいや！　ほら、もっと胸張って！","ENG":"Whatcha need is some self-respect! Keep your chin up!","TWN":"你要對自己更有自信！抬頭挺胸！"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 그럼 우리 타임 캡슐을 만들어 보는 거 어때?","JPN":"あ、じゃあタイムカプセルを作ってみるのはどう？","ENG":"Hey, why don’t we make a time capsule?","TWN":"這樣吧！不如做個時空膠囊怎麼樣？"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오오, 좋네! 나중에 어른이 되면 다 같이 모여가 열어보는기다! 약속이래이!","JPN":"おお、ええやん！　後で大人になったら、みんな集まって開けてみよ！　約束やで！","ENG":"Oh goodie! Y’all are goin’ to gather after we’ve grown up, and we’re gonna open this together! It’s a promise!","TWN":"喔喔，不錯喔！等長大後再一起打開來看！說好囉！"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……저도 좋아요.","JPN":"……僕も賛成です。","ENG":"...Cool with me as well.","TWN":"……我也同意。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_NULL","text":{"KOREA":"멍! 멍!","JPN":"ワン！　ワン！","ENG":"Woof! Woof!","TWN":"汪汪！"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"얘들아……. 미안한데.","JPN":"みんな……聞いて。","ENG":"Guys... I’m really sorry, but...","TWN":"大家……不好意思，"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"문제가 생겼어…… 중대한 문제.","JPN":"問題が起きた……重大な問題。","ENG":"We have a problem... A big problem.","TWN":"發生……大問題。"},"stage":{"bg":"GAMECIRCLE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬? 와 그리 심각한 표정인데? 무섭게시리.","JPN":"何や？　なんでそんな深刻な顔してるん。怖いやん。","ENG":"What is it? Why so serious? Ya scarin’ me.","TWN":"怎麼啦？幹啥這麼嚴肅？你別嚇我們。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쌓여있잖아.","JPN":"積まれてる。","ENG":"It’s stacked up high.","TWN":"堆好多，"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"상자…… 저길 봐.","JPN":"箱……あれ見て。","ENG":"The boxes... look.","TWN":"紙箱……你們看。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자, 잠깐!? 연구실 앞에 상자가 엄청 많이 있잖아?","JPN":"え、なに！？　部室の前に箱があんなにたくさん？","ENG":"W-wait! There are way too many boxes over there!","TWN":"怎…怎麼會！？研究室前面堆好多紙箱。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};